   488→/// Run vvx_vacate command
   489→fn run_vacate(args: VacateArgs) -> i32 {
   490→    eprintln!("vacate: removing kit assets...");
   491→    eprintln!("  burc: {}", args.burc.display());
   492→
   493→    let vacate_args = vof::vofe_VacateArgs {
   494→        burc_path: args.burc,
   495→    };
   496→
   497→    match vof::vofe_vacate(&vacate_args) {
   498→        Ok(result) => {
   499→            // Output JSON summary
   500→            let mut output = serde_json::Map::new();
   501→
   502→            let kits: Vec<serde_json::Value> = result.kits_removed
   503→                .iter()
   504→                .map(|k| serde_json::Value::String(k.clone()))
   505→                .collect();
   506→            output.insert("kits_removed".to_string(), serde_json::Value::Array(kits));
   507→
   508→            output.insert("files_deleted".to_string(), serde_json::Value::Number(result.files_deleted.into()));
   509→            output.insert("commands_removed".to_string(), serde_json::Value::Number(result.commands_removed.into()));
   510→            output.insert("hooks_removed".to_string(), serde_json::Value::Number(result.hooks_removed.into()));
   511→
   512→            let sections: Vec<serde_json::Value> = result.claude_sections_collapsed
   513→                .iter()
   514→                .map(|s| serde_json::Value::String(s.clone()))
   515→                .collect();
   516→            output.insert("claude_sections_collapsed".to_string(), serde_json::Value::Array(sections));
   517→
   518→            println!("{}", serde_json::to_string_pretty(&serde_json::Value::Object(output)).unwrap());
   519→
   520→            eprintln!("vacate: success - {} files, {} commands, {} hooks removed",
   521→                result.files_deleted, result.commands_removed, result.hooks_removed);
   522→            0
   523→        }
   524→        Err(e) => {
   525→            eprintln!("vacate: error: {}", e);
   526→            1
   527→        }
   528→    }
   529→}
