   615→/// Build trophy markdown preview (dry-run, no file modifications)
   616→///
   617→/// Returns the markdown content that would be written to the trophy file.
   618→pub fn jjrg_build_trophy_preview(
   619→    gallops: &jjrg_Gallops,
   620→    firemark: &str,
   621→    paddock_content: &str,
   622→    today: &str,
   623→    steeplechase: &[SteeplechaseEntry],
