   197→/// Run the saddle command - return Heat context
   198→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   199→    let gallops = match Gallops::jjrg_load(&args.file) {
   200→        Ok(g) => g,
   201→        Err(e) => {
   202→            eprintln!("jjx_saddle: error: {}", e);
   203→            return 1;
   204→        }
   205→    };
   206→
   207→    let heat_key = args.firemark.jjrf_display();
   208→    let heat = match gallops.heats.get(&heat_key) {
   209→        Some(h) => h,
   210→        None => {
   211→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   212→            return 1;
   213→        }
   214→    };
   215→
   216→    // Check if heat is stabled (cannot saddle stabled heat)
   217→    if heat.status == HeatStatus::Stabled {
   218→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   219→        return 1;
   220→    }
   221→
   222→    // Read paddock file content
   223→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   224→        Ok(content) => content,
   225→        Err(e) => {
   226→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   227→            return 1;
   228→        }
   229→    };
   230→
   231→    // Get recent steeplechase entries
   232→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   233→        firemark: args.firemark.jjrf_as_str().to_string(),
   234→        limit: 10,
   235→    }).unwrap_or_default();
   236→
   237→    // Find first actionable pace (rough or bridled)
   238→    let mut pace_coronet: Option<String> = None;
   239→    let mut pace_silks: Option<String> = None;
   240→    let mut pace_state: Option<String> = None;
   241→    let mut spec: Option<String> = None;
   242→    let mut direction: Option<String> = None;
   243→
   244→    for coronet_key in &heat.order {
   245→        if let Some(pace) = heat.paces.get(coronet_key) {
   246→            if let Some(tack) = pace.tacks.first() {
   247→                match tack.state {
   248→                    PaceState::Rough | PaceState::Bridled => {
   249→                        pace_coronet = Some(coronet_key.clone());
   250→                        pace_silks = Some(tack.silks.clone());
   251→                        pace_state = Some(match tack.state {
   252→                            PaceState::Rough => "rough".to_string(),
   253→                            PaceState::Bridled => "bridled".to_string(),
   254→                            _ => unreachable!(),
   255→                        });
   256→                        spec = Some(tack.text.clone());
   257→                        if tack.state == PaceState::Bridled {
   258→                            direction = tack.direction.clone();
   259→                        }
   260→                        break;
   261→                    }
   262→                    _ => continue,
   263→                }
   264→            }
   265→        }
   266→    }
   267→
   268→    // Determine heat status string
   269→    let status_str = match heat.status {
   270→        HeatStatus::Racing => "racing",
   271→        HeatStatus::Stabled => "stabled",
   272→        HeatStatus::Retired => "retired",
   273→    };
   274→
   275→    // Output plain text format
   276→    println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   277→    println!("Paddock: {}", heat.paddock_file);
   278→    println!();
   279→    println!("Paddock-content:");
   280→    for line in paddock_content.lines() {
   281→        println!("  {}", line);
   282→    }
   283→    println!();
   284→
   285→    if let Some(coronet) = pace_coronet {
   286→        if let Some(silks) = pace_silks {
   287→            if let Some(state) = pace_state {
   288→                println!("Next: {} ({}) [{}]", silks, coronet, state);
   289→                println!();
   290→                if let Some(spec_text) = spec {
   291→                    println!("Spec:");
   292→                    for line in spec_text.lines() {
   293→                        println!("  {}", line);
   294→                    }
   295→                    println!();
   296→                }
   297→                if let Some(dir_text) = direction {
   298→                    println!("Direction:");
   299→                    for line in dir_text.lines() {
   300→                        println!("  {}", line);
   301→                    }
   302→                    println!();
   303→                }
   304→            }
   305→        }
   306→    }
   307→
   308→    // Output recent work table
   309→    if !recent_work.is_empty() {
   310→        println!("Recent-work:");
   311→
   312→        let mut table = jjrp_Table::jjrp_new(vec![
   313→            jjrp_Column::new("Timestamp", jjrp_Align::Left),
   314→            jjrp_Column::new("Commit", jjrp_Align::Left),
   315→            jjrp_Column::new("[A]", jjrp_Align::Left),
   316→            jjrp_Column::new("Identity", jjrp_Align::Left),
   317→            jjrp_Column::new("Subject", jjrp_Align::Left),
   318→        ]);
   319→
   320→        // Measure all rows to compute column widths
   321→        for entry in &recent_work {
   322→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   323→            let identity_str = if let Some(ref coronet) = entry.coronet {
   324→                coronet.clone()
   325→            } else {
   326→                heat_key.clone()
   327→            };
   328→            table.jjrp_measure(&[
   329→                &entry.timestamp,
   330→                &entry.commit,
   331→                &action_str,
   332→                &identity_str,
   333→                &entry.subject,
   334→            ]);
   335→        }
   336→
   337→        // Print header and separator
   338→        table.jjrp_print_header();
   339→        table.jjrp_print_separator();
   340→
   341→        // Print data rows
   342→        for entry in &recent_work {
   343→            let action_str = entry.action.as_ref().map(|a| format!("[{}]", a)).unwrap_or_else(|| "   ".to_string());
   344→            let identity_str = if let Some(ref coronet) = entry.coronet {
   345→                coronet.clone()
   346→            } else {
   347→                heat_key.clone()
   348→            };
   349→            table.jjrp_print_row(&[
   350→                &entry.timestamp,
   351→                &entry.commit,
   352→                &action_str,
   353→                &identity_str,
   354→                &entry.subject,
   355→            ]);
   356→        }
   357→    }
   358→
   359→    0
   360→}
