   374→
   375→/// Run the parade command - display comprehensive Heat status
   376→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   377→    let gallops = match Gallops::jjrg_load(&args.file) {
   378→        Ok(g) => g,
   379→        Err(e) => {
   380→            eprintln!("jjx_parade: error: {}", e);
   381→            return 1;
   382→        }
   383→    };
   384→
   385→    // Determine target type by length
   386→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   387→
   388→    if target_str.len() == 5 {
   389→        // Coronet - pace view
   390→        let coronet = match Coronet::jjrf_parse(&args.target) {
   391→            Ok(c) => c,
   392→            Err(e) => {
   393→                eprintln!("jjx_parade: error: {}", e);
   394→                return 1;
   395→            }
   396→        };
   397→
   398→        // Extract parent firemark
   399→        let firemark = coronet.jjrf_parent_firemark();
   400→        let heat_key = firemark.jjrf_display();
   401→        let heat = match gallops.heats.get(&heat_key) {
   402→            Some(h) => h,
   403→            None => {
   404→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   405→                return 1;
   406→            }
   407→        };
   408→
   409→        // Find pace
   410→        let coronet_key = coronet.jjrf_display();
   411→        let pace = match heat.paces.get(&coronet_key) {
   412→            Some(p) => p,
   413→            None => {
   414→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   415→                return 1;
   416→            }
   417→        };
   418→
   419→        // Display tack history - iterate in reverse order (oldest first)
   420→        if !pace.tacks.is_empty() {
   421→            // Print header with current state from tacks[0]
   422→            let current_tack = &pace.tacks[0];
   423→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   424→            println!("Heat: {}", heat_key);
   425→            println!();
   426→
   427→            // Iterate tacks in reverse order (oldest first)
   428→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   429→                let state_str = zjjrq_pace_state_str(&tack.state);
   430→                let commit_str = if tack.commit == "0000000" {
   431→                    "(no commit)".to_string()
   432→                } else {
   433→                    tack.commit.clone()
   434→                };
   435→
   436→                println!("[{}] {} ({})", index, state_str, commit_str);
   437→                println!("    Silks: {}", tack.silks);
   438→                if let Some(ref direction) = tack.direction {
   439→                    println!("    Direction: {}", direction);
   440→                }
   441→                println!();
   442→                // Indent spec text
   443→                for line in tack.text.lines() {
   444→                    println!("    {}", line);
   445→                }
   446→                println!();
   447→            }
   448→        }
   449→    } else if target_str.len() == 2 {
   450→        // Firemark - heat view
   451→        let firemark = match Firemark::jjrf_parse(&args.target) {
   452→            Ok(fm) => fm,
   453→            Err(e) => {
   454→                eprintln!("jjx_parade: error: {}", e);
   455→                return 1;
   456→            }
   457→        };
   458→
   459→        let heat_key = firemark.jjrf_display();
   460→        let heat = match gallops.heats.get(&heat_key) {
   461→            Some(h) => h,
   462→            None => {
   463→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   464→                return 1;
   465→            }
   466→        };
   467→
   468→        if args.full {
   469→            // Full view: paddock + all specs
   470→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   471→                Ok(content) => content,
   472→                Err(e) => {
   473→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   474→                    return 1;
   475→                }
   476→            };
   477→
   478→            let status_str = match heat.status {
   479→                HeatStatus::Racing => "racing",
   480→                HeatStatus::Stabled => "stabled",
   481→                HeatStatus::Retired => "retired",
   482→            };
   483→
   484→            println!("Heat: {} ({})", heat.silks, heat_key);
   485→            println!("Status: {}", status_str);
   486→            println!("Created: {}", heat.creation_time);
   487→            println!();
   488→            println!("## Paddock");
   489→            println!();
   490→            println!("{}", paddock_content);
   491→            println!();
   492→            println!("## Paces");
   493→            println!();
   494→
   495→            for coronet_key in &heat.order {
   496→                if let Some(pace) = heat.paces.get(coronet_key) {
   497→                    if let Some(tack) = pace.tacks.first() {
   498→                        // Skip complete/abandoned if --remaining
   499→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   500→                            continue;
   501→                        }
   502→                        let state_str = zjjrq_pace_state_str(&tack.state);
