   680→// ============================================================================
   681→// Scout - Search across heats and paces with regex
   682→// ============================================================================
   683→
   684→/// Arguments for scout command
   685→#[derive(Debug)]
   686→pub struct jjrq_ScoutArgs {
   687→    pub file: std::path::PathBuf,
   688→    pub pattern: String,
   689→    pub actionable: bool,
   690→}
   691→
   692→/// Run the scout command - regex search across heats/paces
   693→pub fn jjrq_run_scout(args: jjrq_ScoutArgs) -> i32 {
   694→    use regex::RegexBuilder;
   695→
   696→    let gallops = match Gallops::jjrg_load(&args.file) {
   697→        Ok(g) => g,
   698→        Err(e) => {
   699→            eprintln!("jjx_scout: error: {}", e);
   700→            return 1;
   701→        }
   702→    };
   703→
   704→    // Build case-insensitive regex
   705→    let re = match RegexBuilder::new(&args.pattern)
   706→        .case_insensitive(true)
   707→        .build()
   708→    {
   709→        Ok(r) => r,
   710→        Err(e) => {
   711→            eprintln!("jjx_scout: error: invalid regex pattern: {}", e);
   712→            return 1;
   713→        }
   714→    };
   715→
   716→    // Track which heats have matches (for group headers)
   717→    let mut current_heat_key: Option<String> = None;
   718→
   719→    // Iterate all heats (racing, stabled, retired)
   720→    for (heat_key, heat) in &gallops.heats {
   721→        // Search each pace in order
   722→        for coronet_key in &heat.order {
   723→            if let Some(pace) = heat.paces.get(coronet_key) {
   724→                if let Some(tack) = pace.tacks.first() {
   725→                    // Apply actionable filter if requested
   726→                    if args.actionable {
   727→                        match tack.state {
   728→                            PaceState::Rough | PaceState::Bridled => {},
   729→                            _ => continue,
   730→                        }
   731→                    }
   732→
   733→                    // Search: silks, spec (tack text), direction, paddock content
   734→                    // Use owned strings to avoid lifetime issues
   735→                    let mut match_result: Option<(String, String)> = None;
   736→
   737→                    if re.is_match(&tack.silks) {
   738→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
   739→                    } else if re.is_match(&tack.text) {
   740→                        match_result = Some(("spec".to_string(), tack.text.clone()));
   741→                    } else if let Some(ref direction) = tack.direction {
   742→                        if re.is_match(direction) {
   743→                            match_result = Some(("direction".to_string(), direction.clone()));
   744→                        }
   745→                    } else {
   746→                        // Search paddock content
   747→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
   748→                        if let Ok(content) = fs::read_to_string(paddock_path) {
   749→                            if re.is_match(&content) {
   750→                                match_result = Some(("paddock".to_string(), content));
   751→                            }
   752→                        }
   753→                    }
   754→
   755→                    // If we found a match, output it
   756→                    if let Some((field_name, field_content)) = match_result {
   757→                        // Print heat header if this is a new heat
   758→                        if current_heat_key.as_ref() != Some(heat_key) {
   759→                            println!("{} {}", heat_key, heat.silks);
   760→                            current_heat_key = Some(heat_key.clone());
   761→                        }
   762→
   763→                        // Print pace line
   764→                        let state_str = zjjrq_pace_state_str(&tack.state);
   765→                        println!("  {} [{}] {}", coronet_key, state_str, tack.silks);
   766→
   767→                        // Print match line with context (extract ~60 chars around match)
   768→                        let match_excerpt = zjjrq_extract_match_context(&field_content, &re);
   769→                        println!("    {}: {}", field_name, match_excerpt);
   770→                    }
   771→                }
   772→            }
   773→        }
   774→    }
   775→
   776→    0
   777→}
   778→
   779→/// Extract context around the first regex match in content
   780→fn zjjrq_extract_match_context(content: &str, re: &regex::Regex) -> String {
   781→    if let Some(mat) = re.find(content) {
   782→        let start = mat.start();
   783→        let end = mat.end();
   784→
   785→        // Find context window (30 chars before, 30 chars after)
   786→        let context_before = 30;
   787→        let context_after = 30;
   788→
   789→        let window_start = start.saturating_sub(context_before);
   790→        let window_end = (end + context_after).min(content.len());
   791→
   792→        let mut excerpt = String::new();
   793→        if window_start > 0 {
   794→            excerpt.push_str("...");
   795→        }
   796→        excerpt.push_str(&content[window_start..window_end]);
   797→        if window_end < content.len() {
   798→            excerpt.push_str("...");
   799→        }
   800→
   801→        // Replace newlines with spaces for single-line display
   802→        excerpt.replace('\n', " ").replace('\r', "")
   803→    } else {
   804→        // Shouldn't happen, but fallback to truncated content
   805→        let truncated = content.chars().take(60).collect::<String>();
   806→        if content.len() > 60 {
   807→            format!("{}...", truncated)
   808→        } else {
   809→            truncated
   810→        }
   811→    }
   812→}
