  1042→// ============================================================================
  1043→// Silks Sequence Parsing and Building
  1044→// ============================================================================
  1045→
  1046→/// Parse silks into (base, sequence_number)
  1047→///
  1048→/// Silks ending with a 2-digit sequence number are parsed into base and number.
  1049→/// Format: "foo-bar" -> ("foo-bar", None)
  1050→///         "foo-bar-01" -> ("foo-bar", Some(1))
  1051→///         "foo-bar-42" -> ("foo-bar", Some(42))
  1052→pub fn jjrq_parse_silks_sequence(silks: &str) -> (String, Option<u32>) {
  1053→    // Use regex ^(.+)-(\d{2})$ for suffix detection
  1054→    let re = match Regex::new(r"^(.+)-(\d{2})$") {
  1055→        Ok(r) => r,
  1056→        Err(_) => {
  1057→            // Fallback: return full silks as base, no sequence
  1058→            return (silks.to_string(), None);
  1059→        }
  1060→    };
  1061→
  1062→    if let Some(caps) = re.captures(silks) {
  1063→        if let (Some(base_match), Some(num_match)) = (caps.get(1), caps.get(2)) {
  1064→            let base = base_match.as_str().to_string();
  1065→            if let Ok(num_str) = num_match.as_str().parse::<u32>() {
